-- Supabase PostgreSQL 시연용 회사·딜러 이탈 분석 데이터
-- 생성 기준: dataset/dummy_output의 기존 딜러 100명·회사 20개 더미 데이터
-- 시연 계정 공통 비밀번호: Demo1234!
-- 실제 서비스 DB가 아닌 개발/시연용 Supabase 프로젝트에서 실행하세요.
-- 백엔드 활동 요약 Entity/Repository는 아래 테이블·컬럼명과 동일하게 연결해야 합니다.

BEGIN;

DO $$
BEGIN
    IF to_regclass('public.companies') IS NULL THEN
        RAISE EXCEPTION 'public.companies 테이블이 없습니다. Spring Boot 기본 테이블을 먼저 생성하세요.';
    END IF;
    IF to_regclass('public.dealers') IS NULL THEN
        RAISE EXCEPTION 'public.dealers 테이블이 없습니다. Spring Boot 기본 테이블을 먼저 생성하세요.';
    END IF;
END
$$;

CREATE TABLE IF NOT EXISTS public.dealer_activity_summaries (
    dealer_activity_summary_id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    dealer_id BIGINT NOT NULL UNIQUE
        REFERENCES public.dealers(dealer_id) ON DELETE CASCADE,
    last_activity_days INTEGER NOT NULL CHECK (last_activity_days >= 0),
    recent_60d_trade_count INTEGER NOT NULL CHECK (recent_60d_trade_count >= 0),
    previous_trade_count INTEGER NOT NULL CHECK (previous_trade_count >= 0),
    site_usage_rate DOUBLE PRECISION NOT NULL CHECK (site_usage_rate BETWEEN 0 AND 1),
    calculated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS public.company_activity_summaries (
    company_activity_summary_id BIGINT GENERATED BY DEFAULT AS IDENTITY PRIMARY KEY,
    company_id BIGINT NOT NULL UNIQUE
        REFERENCES public.companies(company_id) ON DELETE CASCADE,
    dealer_count INTEGER NOT NULL CHECK (dealer_count >= 0),
    active_dealer_ratio DOUBLE PRECISION NOT NULL CHECK (active_dealer_ratio BETWEEN 0 AND 1),
    recent_trade_count INTEGER NOT NULL CHECK (recent_trade_count >= 0),
    previous_trade_count INTEGER NOT NULL CHECK (previous_trade_count >= 0),
    activity_growth DOUBLE PRECISION,
    site_usage_rate_avg DOUBLE PRECISION NOT NULL CHECK (site_usage_rate_avg BETWEEN 0 AND 1),
    calculated_at TIMESTAMPTZ NOT NULL DEFAULT NOW()
);

