INSERT INTO public.dealers (
    company_id,
    login_id,
    password,
    name,
    phone,
    profile_image_url,
    status,
    tier,
    risk_score,
    created_at,
    updated_at
)
SELECT
    company.company_id,
    source.login_id,
    source.password,
    source.name,
    source.phone,
    source.profile_image_url,
    source.status,
    source.tier,
    NULL,
    source.created_at,
    source.updated_at
FROM dealer_source source
JOIN public.companies company
  ON company.business_number = source.company_business_number
ON CONFLICT (login_id) DO UPDATE SET
    company_id = EXCLUDED.company_id,
    password = EXCLUDED.password,
    name = EXCLUDED.name,
    phone = EXCLUDED.phone,
    profile_image_url = EXCLUDED.profile_image_url,
    status = EXCLUDED.status,
    tier = EXCLUDED.tier,
    risk_score = NULL,
    updated_at = EXCLUDED.updated_at;

