INSERT INTO public.dealer_activity_summaries (
    dealer_id,
    last_activity_days,
    recent_60d_trade_count,
    previous_trade_count,
    site_usage_rate,
    calculated_at
)
SELECT
    dealer.dealer_id,
    source.last_activity_days,
    source.recent_60d_trade_count,
    source.previous_trade_count,
    source.site_usage_rate,
    source.calculated_at
FROM dealer_summary_source source
JOIN public.dealers dealer
  ON dealer.login_id = source.dealer_login_id
ON CONFLICT (dealer_id) DO UPDATE SET
    last_activity_days = EXCLUDED.last_activity_days,
    recent_60d_trade_count = EXCLUDED.recent_60d_trade_count,
    previous_trade_count = EXCLUDED.previous_trade_count,
    site_usage_rate = EXCLUDED.site_usage_rate,
    calculated_at = EXCLUDED.calculated_at;

