INSERT INTO public.company_activity_summaries (
    company_id,
    dealer_count,
    active_dealer_ratio,
    recent_trade_count,
    previous_trade_count,
    activity_growth,
    site_usage_rate_avg,
    calculated_at
)
SELECT
    company.company_id,
    source.dealer_count,
    source.active_dealer_ratio,
    source.recent_trade_count,
    source.previous_trade_count,
    source.activity_growth,
    source.site_usage_rate_avg,
    source.calculated_at
FROM company_summary_source source
JOIN public.companies company
  ON company.business_number = source.company_business_number
ON CONFLICT (company_id) DO UPDATE SET
    dealer_count = EXCLUDED.dealer_count,
    active_dealer_ratio = EXCLUDED.active_dealer_ratio,
    recent_trade_count = EXCLUDED.recent_trade_count,
    previous_trade_count = EXCLUDED.previous_trade_count,
    activity_growth = EXCLUDED.activity_growth,
    site_usage_rate_avg = EXCLUDED.site_usage_rate_avg,
    calculated_at = EXCLUDED.calculated_at;

COMMIT;

-- 실행 결과 확인: 아래 네 값이 각각 20, 100, 100, 20이어야 합니다.
SELECT COUNT(*) AS demo_company_count
FROM public.companies
WHERE business_number LIKE '999-81-%';

SELECT COUNT(*) AS demo_dealer_count
FROM public.dealers
WHERE login_id LIKE 'demo_dealer_%';

SELECT COUNT(*) AS demo_dealer_summary_count
FROM public.dealer_activity_summaries summary
JOIN public.dealers dealer ON dealer.dealer_id = summary.dealer_id
WHERE dealer.login_id LIKE 'demo_dealer_%';

SELECT COUNT(*) AS demo_company_summary_count
FROM public.company_activity_summaries summary
JOIN public.companies company ON company.company_id = summary.company_id
WHERE company.business_number LIKE '999-81-%';
